css:
.loader {
  width: 180px;
  height: 180px;
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
}
.circle {
  width: 150px;
  height: 150px;
  border-radius: 52% 48% 58% 42%;
  border: 9px solid;
  position: absolute;
  box-sizing: border-box;
}
.c1 { animation: wildRingTurn 2.2s linear infinite; border-color: #ff9f1c; }
.c2 { animation: wildRingTurn 3s linear infinite reverse; border-color: #ff365e; }
.c3 { animation: wildRingTurn 2s linear infinite; border-color: #ffffff; opacity: .5; }
.c4 { animation: wildRingTurn 1s linear infinite reverse; border-color: #7dd3fc; opacity: .8; }
@keyframes wildRingTurn { to { transform: rotate(360deg); } }
